<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<title>Bouncing Ball Playground</title>
<style>
  body { margin:0; background:#222;color:#eee;font-family:sans-serif;display:flex;flex-direction:column;align-items:center;height:100vh;}
  #controls{margin-top:10px;}
  button{margin:0 5px;padding:8px 12px;background:#444;border:none;color:white;cursor:pointer;}
  button:hover{background:#555;}
  canvas{border:1px solid #555;background:#111;}
</style>
</head>
<body>
<canvas id="sim" width="400" height="400"></canvas>
<div id="controls">
  <button id="drop">Drop Ball</button>
  <button id="play">Pause</button>
  <button id="clear">Clear</button>
</div>

<script>
(() => {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');
  const w = canvas.width, h = canvas.height;
  const gravity = 0.5; // pixels per frame^2
  const restitution = 0.9;
  let ballsList = [];
  let running = false;
  let animId;

  function draw() {
    ctx.clearRect(0,0,w,h);
    for (const b of ballsList) {
      ctx.beginPath();
      ctx.arc(b.x,b.y,b.r,0,Math.PI*2);
      ctx.fillStyle='#ff6';
      ctx.fill();
      ctx.strokeStyle='#ffa';
      ctx.stroke();
    }
  }

  function step(dt=1){
    for (const b of ballsList) {
      // apply gravity
      b.vy += gravity * dt;
      // update position
      b.x += b.vx * dt;
      b.y += b.vy * dt;

      // collision with walls
      if(b.x - b.r < 0){
        b.x = b.r;
        b.vx *= -restitution;
      } else if(b.x + b.r > w){
        b.x = w - b.r;
        b.vx *= -restitution;
      }
      if(b.y - b.r < 0){
        b.y = b.r;
        b.vy *= -restitution;
      } else if(b.y + b.r > h){
        b.y = h - b.r;
        b.vy *= -restitution;
      }
    }
    draw();
  }

  function loop(){
    step();
    animId = requestAnimationFrame(loop);
  }

  // API
  window.sim = {
    w, h,
    balls: () => ballsList.map(b=>({...b})),
    addBall: (x,y,vx=0,vy=0,r=15)=>{
      const b={x,y,vx,vy,r};
      ballsList.push(b);
      draw();
    },
    clear: ()=>{
      ballsList=[];
      draw();
    },
    step
  };

  // UI events
  document.getElementById('drop').addEventListener('click',()=>{
    const x = Math.random()*w;
    const y = Math.random()*h/2;
    window.sim.addBall(x,y,0,-Math.random()*5+1);
  });
  document.getElementById('clear').addEventListener('click',()=>window.sim.clear());
  document.getElementById('play').addEventListener('click',function(){
    running=!running;
    this.textContent = running?'Pause':'Play';
    if(running) loop();
    else cancelAnimationFrame(animId);
  });
  canvas.addEventListener('click',(e)=>{
    const rect=canvas.getBoundingClientRect();
    const x=e.clientX-rect.left;
    const y=e.clientY-rect.top;
    window.sim.addBall(x,y,0,-5);
  });

  // initial draw
  draw();
})();
</script>
</body>
</html>
